import { Link, useNavigate }

from "react-router-dom";

function Navbar() {

    const navigate = useNavigate();

    const handleLogout = () => {

        localStorage.removeItem(
            "token"
        );

        localStorage.removeItem(
            "customerId"
        );

        alert("Logout Successful");

        navigate("/login");
    };

    return (

        <div
            style={{
                backgroundColor: "black",

                padding: "15px",

                display: "flex",

                gap: "20px"
            }}
        >

            <Link
                to="/"

                style={{
                    color: "white",

                    textDecoration: "none"
                }}
            >
                Home
            </Link>

            <Link
                to="/register"

                style={{
                    color: "white",

                    textDecoration: "none"
                }}
            >
                Register
            </Link>

            <Link
                to="/login"

                style={{
                    color: "white",

                    textDecoration: "none"
                }}
            >
                Login
            </Link>

            <Link
                to="/my-bookings"

                style={{
                    color: "white",

                    textDecoration: "none"
                }}
            >
                My Bookings
            </Link>

            <button

                onClick={handleLogout}

                style={{
                    backgroundColor: "red",

                    color: "white",

                    border: "none",

                    padding: "5px 10px",

                    cursor: "pointer"
                }}
            >

                Logout

            </button>

        </div>
    );
}

export default Navbar;
